  from jsonb_array_elements($catalogue$[{"id":"CND-001","name":"Aesperic Burn","region":"Asura","type":"Magical Ailment","exposure":"Damaged Aesperium conduit, unstable airship core, failed enchantment","save":"Vitality or Arcana DC 55","mark1":"Blue-green veins and copper taste","mark2":"-25 to all saves against magical attacks","mark3":"First spell each scene costs +5 MP or glitches","crisis":"Nearby magical devices misidentify or react to victim","treatment":"Grounding iron, anti-mana charcoal, 3 nights from active conduits","tags":"Magic, Mana, Asura"},{"id":"CND-002","name":"Glassfin Fever","region":"Asura","type":"Sickness","exposure":"Contaminated canal fish or mana-damaged city water","save":"Vitality DC 50","mark1":"Cloudy eyes and numb fingers","mark2":"-10 passive perception","mark3":"Disadvantage on checks involving magical light or illusions","crisis":"Phantom reflections reveal false spellcasters","treatment":"Purified water, salt purge, anti-mana detox","tags":"Water, Magic, Asura"},{"id":"CND-003","name":"The Inventor's Claim","region":"Asura","type":"Curse","exposure":"Using a patented magical invention without permission","save":"No save, activates on violation","mark1":"Faint serial number appears on skin","mark2":"Guild wards can identify victim","mark3":"Constructs and registry devices become suspicious","crisis":"Owner or guild can track the cursed user","treatment":"Return, destroy, or legally release the patented item","tags":"Contract, Arcane, Asura"},{"id":"CND-004","name":"White-Lung","region":"Ronoa","type":"Sickness","exposure":"Wet cold, sleeping in snow, frozen cave exposure","save":"Vitality DC 55","mark1":"Frosted cough and cracked lips","mark2":"Reduced movement in freezing terrain","mark3":"Disadvantage on Speed and Vitality checks in cold","crisis":"Collapse into deathlike cold sleep","treatment":"Heat, dry shelter, Brumox Winter Pot, smoked herbs","tags":"Cold, Ronoa, Survival"},{"id":"CND-005","name":"Whisperwind Fever","region":"Ronoa","type":"Magical Ailment","exposure":"Listening too long to old winds, runic mountain sites","save":"Awareness DC 60","mark1":"Hears distant names and battle songs","mark2":"Receive one clue but lose restful sleep","mark3":"Disadvantage on solo navigation","crisis":"Follows a false voice toward danger","treatment":"Firelight, communal music, companions speaking present names","tags":"Wind, Rune, Ronoa"},{"id":"CND-006","name":"Cairn-Bound","region":"Ronoa","type":"Curse","exposure":"Abandoning a companion, desecrating a cairn, breaking a mountain oath","save":"No save, activates on betrayal","mark1":"Footprints subtly point back toward the broken oath","mark2":"Shelter and gear freeze at bad moments","mark3":"Haunted by calls for help during storms","crisis":"Cannot benefit from cold shelter until duty is faced","treatment":"Recover the dead, rebuild cairn, fulfill oath","tags":"Death, Oath, Ronoa"},{"id":"CND-007","name":"Fittoan Ash-Sickness","region":"Fittoa","type":"Magical Sickness","exposure":"Inhaling red ash, mist exposure, contaminated relics, ruin collapse","save":"Vitality DC 55 to 85","mark1":"Soot tongue, red cough, distant bell sounds","mark2":"-5 Vitality and Dis/Survival dreams of unfamiliar places","mark3":"Disadvantage on first Awareness, Insight, or Navigation check daily","crisis":"Identity slips; false roads, echo-self, or ruin separation","treatment":"Hushback Silver-Reed Broth, clean camp, identity-anchor ritual, Soul Sanctuary","tags":"Red Ash, Soul, Memory, Fittoa"},{"id":"CND-008","name":"Echo Fever","region":"Fittoa","type":"Magical Ailment","exposure":"Looping ruins, speaking to echoes, witnessing alternate lives","save":"Awareness DC 60","mark1":"Memory gaps and incorrect certainty","mark2":"-5 Intelligence and disadvantage on memory checks","mark3":"Recall useful clues from another timeline","crisis":"Acts on a false memory as though it is current","treatment":"Write events down, group confirmation, avoid solo rest","tags":"Time, Memory, Fittoa"},{"id":"CND-009","name":"Broken Bell Debt","region":"Fittoa","type":"Curse","exposure":"Stealing memory-objects, ignoring warnings, lying about a death","save":"No save, activates on offense","mark1":"Hears an unexplained bell before danger","mark2":"Warnings are early, false, or meant for someone else","mark3":"Bell interrupts rest and concentration","crisis":"Ruin or echo begins actively calling victim by name","treatment":"Return object, name the forgotten dead, answer the original warning","tags":"Bell, Debt, Fittoa"},{"id":"CND-010","name":"Gravewake Blight","region":"Karrnath","type":"Sickness","exposure":"Gravefield water, corpse dust, undead labor sites","save":"Vitality DC 55","mark1":"Cold skin and slowed pulse","mark2":"All healing reduced by half","mark3":"Magical healing restores half normal value","crisis":"Sleepwalks toward graves or necromantic sources","treatment":"Sun exposure, salt bath, burial rite, Blackwake Vigil Soup","tags":"Undead, Grave, Karrnath"},{"id":"CND-011","name":"Marrow Rot","region":"Karrnath","type":"Ailment","exposure":"Failed fleshcrafting, bone-shaping residue, unsafe marrow","save":"Vitality DC 60","mark1":"Joint pain and black bruises","mark2":"-5 Speed and disadvantage on Acrobatics","mark3":"Evasion halved","crisis":"Bone growths form beneath the skin","treatment":"Bone-salt poultice, rest, anti-necromantic ritual","tags":"Flesh, Bone, Karrnath"},{"id":"CND-012","name":"The Unburied Contract","region":"Karrnath","type":"Curse","exposure":"Taking inheritance, wages, or property owed to the dead","save":"No save, activates on theft","mark1":"Coins become cold; ledger sounds at night","mark2":"Dead recognize victim as indebted","mark3":"Spirits demand a task or repayment","crisis":"A named dead creditor manifests or claims property","treatment":"Settle debt, fulfill final obligation, negotiate inheritance","tags":"Death, Debt, Karrnath"},{"id":"CND-013","name":"River-Salt Fever","region":"Shirone","type":"Sickness","exposure":"Floodwater, stagnant temple canals, contaminated milk","save":"Vitality DC 50","mark1":"Fever, cramps, blue-white salt on wounds","mark2":"-5 Vitality","mark3":"Disadvantage against poison and exhaustion","crisis":"Cannot retain water without ritual aid","treatment":"Temple salt, boiled Nayara peel, clean water, river-clay poultice","tags":"Water, Temple, Shirone"},{"id":"CND-014","name":"Pilgrim's Halo","region":"Shirone","type":"Divine Ailment","exposure":"Traveling a holy route with guilt, false vows, or stolen relics","save":"Awareness DC 60","mark1":"Faint halo visible in darkness","mark2":"Pain when lying about purpose","mark3":"Cannot comfortably leave the sacred road","crisis":"Nearby people share visions of guilt","treatment":"Confession, restitution, honest completion of pilgrimage","tags":"Faith, Oath, Shirone"},{"id":"CND-015","name":"Naga's Judgment","region":"Shirone","type":"Curse","exposure":"Betraying someone under protection or weaponizing holy law","save":"No save, activates on offense","mark1":"Serpent-shaped bruise appears","mark2":"Lies physically hurt","mark3":"Voice hisses while speaking injustice","crisis":"Temple wards and paladins sense deception easily","treatment":"Public confession, protect harmed person, selfless mercy","tags":"Faith, Justice, Shirone"},{"id":"CND-016","name":"Barkblood","region":"Milis","type":"Sickness","exposure":"Forest spores, sacred fungi, infected grove wounds","save":"Vitality DC 55","mark1":"Green-brown veins and barklike scars","mark2":"-5 Speed","mark3":"Natural healing slows","crisis":"Roots bind victim in place during sleep","treatment":"Barkbee propolis, grove medicine, permission from local tree-line","tags":"Forest, Milis, Nature"},{"id":"CND-017","name":"Green Sleep","region":"Milis","type":"Magical Ailment","exposure":"Dream pollen, sleeping beneath ancient trees","save":"Awareness DC 60","mark1":"Dreams an entire lifetime overnight","mark2":"Cannot gain full rest unless awakened by name","mark3":"Believes forest memories are their own","crisis":"Refuses to leave the grove or becomes lost in dreamscape","treatment":"Named awakening, sacred tea, companion anchor","tags":"Dream, Forest, Milis"},{"id":"CND-018","name":"Tree-Line Severance","region":"Milis","type":"Curse","exposure":"Cutting sacred trees, breaking grove claims, harming migration beasts","save":"No save, activates on offense","mark1":"Shadow becomes rootlike","mark2":"Wild animals avoid or stalk victim","mark3":"Plants subtly hinder travel","crisis":"Grove itself recognizes victim as intruder","treatment":"Restore damage, plant replacement, swear duty to grove","tags":"Grove, Nature, Milis"},{"id":"CND-019","name":"Moonwell Fever","region":"Begaritt","type":"Sickness","exposure":"Unregistered well, ruin cistern, tainted oasis water","save":"Vitality DC 55","mark1":"Silver tears and cracked lips","mark2":"-5 Vitality and -10 Vitality in heat","mark3":"Requires twice normal water","crisis":"Heard water leads victim into ruins or dunes","treatment":"Water from rightful Water-Name holder, salts, Qasira pulp","tags":"Water, Desert, Begaritt"},{"id":"CND-020","name":"Glassbite","region":"Begaritt","type":"Ailment","exposure":"Glass-sand storm, buried battlefield, mirage field","save":"Speed or Vitality DC 60","mark1":"Fine glass fragments in skin","mark2":"-5 Speed and disadvantge on Stealth","mark3":"Bright sunlight causes pain","crisis":"Scars reflect scenes behind victim","treatment":"Moonlight extraction, oil bath, careful Medicine","tags":"Glass, Desert, Begaritt"},{"id":"CND-021","name":"The Third Thirst","region":"Begaritt","type":"Curse","exposure":"Hoarding water in crisis, forging Water-Names, denying survival water","save":"No save, activates on offense","mark1":"Thirst remains after third swallow","mark2":"Water gives no relief during travel","mark3":"Thirst imposes disadvantage in heat","crisis":"Victim will drink cursed or unsafe water willingly","treatment":"Share water in danger, restore Water-Name, protect a well","tags":"Water, Curse, Begaritt"},{"id":"CND-022","name":"Cinderlung","region":"Demon Continent","type":"Sickness","exposure":"Volcanic ash, forge smoke, ashfold exposure","save":"Vitality DC 55","mark1":"Black cough and heat in ribs","mark2":"-5 Vitality saves","mark3":"Disadvantage on forced marches or heat checks","crisis":"Breath may ignite dry material near flame","treatment":"Cold mineral water, ashcloth filters, steam-cave rest","tags":"Ash, Fire, Demon Continent"},{"id":"CND-023","name":"Warfire Rot","region":"Demon Continent","type":"Ailment","exposure":"Infected battle wound, demon-beast blood, heat-cursed weapon","save":"Vitality DC 60","mark1":"Wound closes too fast then reopens","mark2":"First fire damage each combat deals +2d8 damage","mark3":"Anger or fear reopens old wounds","crisis":"Wound becomes a living fire curse","treatment":"Cooling salves, bloodletting, identify wound origin","tags":"Fire, Wound, Demon Continent"},{"id":"CND-024","name":"Banner Scar","region":"Demon Continent","type":"Curse","exposure":"Desecrating or falsely swearing beneath a war banner","save":"No save, activates on offense","mark1":"War symbol appears on skin","mark2":"Commands near banners become difficult to resist","mark3":"Enemy standards trigger fear or compulsion","crisis":"Banner-owner can issue a direct curse-command","treatment":"Defeat owner, burn banner willingly, swear protective oath","tags":"War, Command, Demon Continent"},{"id":"CND-025","name":"Cloudfade","region":"Heaven Continent","type":"Magical Ailment","exposure":"Long exposure to mist terraces, impossible altitude, northern lights","save":"Awareness DC 65","mark1":"Voice and steps become faint","mark2":"-5 Talent and disadvantage on Persuasion","mark3":"Allies must consciously remember victim during plans","crisis":"Victim cannot be recognized without an anchor","treatment":"Warm meal, touch, spoken names, beloved personal object","tags":"Mist, Identity, Heaven"},{"id":"CND-026","name":"Aurora Blindness","region":"Heaven Continent","type":"Sickness","exposure":"Staring into reflected auroras, celestial ice, sky ruins","save":"Awareness DC 65","mark1":"Colored halos appear around creatures","mark2":"May see magical auras but normal sight worsens","mark3":"Disadvantage on sight-based checks","crisis":"Illusion and reality become indistinguishable","treatment":"Darkness, covered eyes, Halor oil, trusted guide","tags":"Light, Vision, Heaven"},{"id":"CND-027","name":"The Still Prayer","region":"Heaven Continent","type":"Curse","exposure":"Asking divinity to preserve what must be allowed to change","save":"No save, activates through prayer","mark1":"Stops aging temporarily","mark2":"Resists emotional change and loss","mark3":"Cannot accept departure, grief, or new bonds","crisis":"Becomes spiritually frozen in one moment","treatment":"Release something precious, forgive, let a memory remain incomplete","tags":"Time, Faith, Heaven"}]$catalogue$::jsonb) with ordinality
