insert into public.catalogue_entries (category, stable_key, sort_order, data)
select
  'items',
  'items:' || sort_order::text,
  sort_order,
  data
from source_entries
on conflict (category, stable_key) do nothing;

with source_entries as (
  select value as data, ordinality::integer - 1 as sort_order
  from jsonb_array_elements($catalogue$[{"name":"Lysael Glassfin Parcels","region":"Asura","cost":7,"method":"Steamed fish, curd, canal herbs, Lysael pear glaze wrapped in reed leaves.","effect":"Once, gain +5 to Arcana, Research, Investigation, or a tool check involving magic or machinery."},{"name":"Vellhorn Cloud Curd","region":"Asura","cost":4,"method":"Whipped Vellhorn cheese, Lysael preserve, honey, oat crumble. Served cold.","effect":"During your next short rest, regain 2 HP or 10 MP."},{"name":"Brumox Winter Pot","region":"Ronoa","cost":5,"method":"Slow-cooked Brumox meat, roots, smoked broth, dark bread, Skalven berries.","effect":"Gain 5 temporary HP and reduce ordinary cold penalties for 1 hour."},{"name":"Hrimchar Smoke-Cakes","region":"Ronoa","cost":3,"method":"Smoked fish, rye meal, oats, goose egg, fried on iron.","effect":"Once, gain +5 to Survival or Perception involving weather, tracks, routes, or wilderness danger."},{"name":"Hushback Silver-Reed Broth","region":"Fittoa","cost":8,"method":"Hushback milk, charcoal root, oats, bitter herbs. Tested with silver before serving.","effect":"Once, gain +5 to resist poison, disease, contamination, or unstable terrain."},{"name":"Telleth Bellbread ⚠","region":"Fittoa","cost":25,"method":"Telleth rind steeped in honey-tea, brushed over hard oat bread, baked dry.","effect":"Recall one extra sensory detail from a location, object, or person examined in the last 24 hours."},{"name":"Duskhide Marrow Tartine","region":"Karrnath","cost":6,"method":"Roasted marrow, black rye, black salt, Morvane-vinegar reduction.","effect":"The first time you take damage in your next combat, reduce it by 5."},{"name":"Blackwake Vigil Soup","region":"Karrnath","cost":5,"method":"Lamprey, dark greens, onion, vinegar, dried Morvane skins.","effect":"Once, gain +5 to Medicine, Religion, Insight, or Investigation involving death, wounds, corpses, undead, or grief."},{"name":"Azurefin Nayara Skewers","region":"Shirone","cost":4,"method":"Nayara-marinated fish grilled over open flame with temple salt.","effect":"Once, gain +5 against being shoved, grappled, restrained, or knocked prone."},{"name":"Reedhorn Yoghurt Hearthbread","region":"Shirone","cost":3,"method":"Warm flatbread topped with cold Reedhorn yoghurt, Nayara zest, herbs, and salt.","effect":"Once, gain +5 to Persuasion, Insight, or Medicine."},{"name":"Vaelwyn Bark-Honey Dumplings","region":"Milis","cost":8,"method":"Twin Vaelwyn pears browned in bark honey and steamed in leaf baskets.","effect":"When you Help an ally on a non-combat check, they gain an additional +10."},{"name":"Qasira Well-Bowl","region":"Begaritt","cost":5,"method":"Cold Qasira fruit pulp, yoghurt, Khezir peel, toasted grain, desert salt.","effect":"Ignore ordinary heat and thirst penalties for 1 hour."},{"name":"Gorak Ash-Roast","region":"Demon Continent","cost":6,"method":"Gorak fruit, eel, Taruzh pickle, ash salt, buried beneath hot coals.","effect":"Once, gain +5 to a Strength or Vitality saving throw."},{"name":"Iril Candle-Pear ✦","region":"Heaven Continent","cost":30,"method":"Iril pear warmed in sealed glass with a drop of Halor oil. Never allowed to boil.","effect":"Once, gain +5 to an Awareness save against fear, magical sleep, cold, or disorientation."}]$catalogue$::jsonb) with ordinality
+)
insert into public.catalogue_entries (category, stable_key, sort_order, data)
select
  'food_dishes',
  'food_dishes:' || sort_order::text,
  sort_order,
  data
